import type { ToolPlugin } from "../manager";
import { tasks, type Task } from "../../task_tracker";

interface TaskInfo {
  id: string;
  title: string;
  description: string;
  status: Task['status'];
  priority: Task['priority'];
  progress: number;
  subtaskCount: number;
  tags: string[];
  estimatedMinutes?: number;
  actualMinutes?: number;
  createdAt: string;
  completedAt?: string;
  notes: string[];
}

interface TaskListResult {
  success: boolean;
  activeTask?: TaskInfo | null;
  tasks: TaskInfo[];
  stats: {
    total: number;
    pending: number;
    active: number;
    completed: number;
    completionRate: number;
  };
}

interface TaskActionResult {
  success: boolean;
  taskId?: string;
  message: string;
  task?: TaskInfo;
}

function toTaskInfo(task: Task): TaskInfo {
  return {
    id: task.id,
    title: task.title,
    description: task.description,
    status: task.status,
    priority: task.priority,
    progress: tasks.getCompletionPercentage(task.id),
    subtaskCount: task.subtaskIds.length,
    tags: task.tags,
    ...(task.estimatedMinutes !== undefined && { estimatedMinutes: task.estimatedMinutes }),
    ...(task.actualMinutes !== undefined && { actualMinutes: task.actualMinutes }),
    createdAt: task.createdAt,
    ...(task.completedAt !== undefined && { completedAt: task.completedAt }),
    notes: task.notes,
  };
}

